508→export function listFormatRules(
509→  importId: string,
510→  targetFormat?: AdjustmentTargetFormat,
511→) {
512→  const localConditions = [eq(formatRules.importId, importId)];
513→  const profileConditions = [
514→    isNull(formatRules.importId),
515→    eq(formatRules.scope, "format_profile"),
516→  ];
517→
518→  if (targetFormat) {
519→    localConditions.push(eq(formatRules.targetFormat, targetFormat));
520→    profileConditions.push(eq(formatRules.targetFormat, targetFormat));
521→  }
522→
523→  const profileRows = db
524→    .select()
525→    .from(formatRules)
526→    .where(and(...profileConditions))
527→    .orderBy(desc(formatRules.createdAt))
528→    .all();
529→
530→  const localRows = db
531→    .select()
532→    .from(formatRules)
533→    .where(and(...localConditions))
534→    .orderBy(desc(formatRules.createdAt))
535→    .all();
536→
537→  return [...profileRows, ...localRows].map(deserializeFormatRule);
538→}
