540→export function getAdjustmentMetrics(
541→  importId: string,
542→  targetFormat: AdjustmentTargetFormat,
543→): AdjustmentMetrics {
544→  const row = db.get<{
545→    sessions_created: number | null;
546→    clarifications: number | null;
547→    previews_generated: number | null;
548→    preview_failures: number | null;
549→    rules_applied: number | null;
550→    rules_disabled: number | null;
551→    sessions_discarded: number | null;
552→    updated_at: string | null;
553→  }>(sql`
554→    SELECT
555→      SUM(CASE WHEN event_type = 'session_created' THEN 1 ELSE 0 END) AS sessions_created,
556→      SUM(CASE WHEN event_type = 'clarification_requested' THEN 1 ELSE 0 END) AS clarifications,
557→      SUM(CASE WHEN event_type = 'preview_generated' THEN 1 ELSE 0 END) AS previews_generated,
558→      SUM(CASE WHEN event_type = 'preview_failed' THEN 1 ELSE 0 END) AS preview_failures,
559→      SUM(CASE WHEN event_type = 'rule_applied' THEN 1 ELSE 0 END) AS rules_applied,
560→      SUM(CASE WHEN event_type = 'rule_disabled' THEN 1 ELSE 0 END) AS rules_disabled,
561→      SUM(CASE WHEN event_type = 'session_discarded' THEN 1 ELSE 0 END) AS sessions_discarded,
562→      MAX(created_at) AS updated_at
563→    FROM ${adjustmentEvents}
564→    WHERE ${adjustmentEvents.importId} = ${importId}
565→      AND ${adjustmentEvents.targetFormat} = ${targetFormat}
566→  `);
567→
568→  return adjustmentMetricsSchema.parse({
569→    counts: {
570→      clarifications: toCount(row?.clarifications ?? 0),
571→      previewFailures: toCount(row?.preview_failures ?? 0),
572→      previewsGenerated: toCount(row?.previews_generated ?? 0),
573→      rulesApplied: toCount(row?.rules_applied ?? 0),
574→      rulesDisabled: toCount(row?.rules_disabled ?? 0),
575→      sessionsCreated: toCount(row?.sessions_created ?? 0),
576→      sessionsDiscarded: toCount(row?.sessions_discarded ?? 0),
577→    },
578→    importId,
579→    targetFormat,
580→    updatedAt: row?.updated_at ?? null,
581→  });
582→}
