584→export function updateFormatRuleStatus(
585→  ruleId: string,
586→  status: FormatRule["status"],
587→) {
588→  const existingRule = getFormatRule(ruleId);
589→
590→  if (!existingRule) {
591→    throw new Error("Formatregel nicht gefunden.");
592→  }
593→
594→  const timestamp = now();
595→
596→  db.update(formatRules)
597→    .set({
598→      status,
599→      updatedAt: timestamp,
600→    })
601→    .where(eq(formatRules.id, ruleId))
602→    .run();
603→
604→  const nextRule = getFormatRule(ruleId);
605→
606→  if (!nextRule) {
607→    throw new Error("Formatregel konnte nicht neu geladen werden.");
608→  }
609→
610→  return nextRule;
611→}
