613→export function promoteRuleToProfile(ruleId: string) {
614→  const existingRule = getFormatRule(ruleId);
615→
616→  if (!existingRule) {
617→    throw new Error("Formatregel nicht gefunden.");
618→  }
619→
620→  if (existingRule.scope === "format_profile") {
621→    throw new Error("Regel ist bereits eine Profil-Regel.");
622→  }
623→
624→  const originalImportId = existingRule.importId;
625→  const timestamp = now();
626→
627→  db.transaction((tx) => {
628→    tx.update(formatRules)
629→      .set({
630→        scope: "format_profile",
631→        importId: null,
632→        updatedAt: timestamp,
633→      })
634→      .where(eq(formatRules.id, ruleId))
635→      .run();
636→
637→    if (!originalImportId) {
638→      throw new Error(
639→        "Regel hat keine gültige importId – Promote nicht möglich.",
640→      );
641→    }
642→
643→    recordAdjustmentEvent(
644→      {
645→        importId: originalImportId,
646→        ruleId: existingRule.id,
647→        sessionId: existingRule.sourceSessionId,
648→        targetFormat: existingRule.targetFormat,
649→        type: "rule_promoted",
650→      },
651→      tx,
652→    );
653→  });
654→
655→  const nextRule = getFormatRule(ruleId);
656→
657→  if (!nextRule) {
658→    throw new Error("Formatregel konnte nicht neu geladen werden.");
659→  }
660→
661→  return nextRule;
662→}
