664→export function demoteRuleToLocal(ruleId: string, importId: string) {
665→  const existingRule = getFormatRule(ruleId);
666→
667→  if (!existingRule) {
668→    throw new Error("Formatregel nicht gefunden.");
669→  }
670→
671→  if (existingRule.scope !== "format_profile") {
672→    throw new Error("Regel ist bereits lokal.");
673→  }
674→
675→  const timestamp = now();
676→
677→  db.transaction((tx) => {
678→    tx.update(formatRules)
679→      .set({
680→        scope: "import_local",
681→        importId,
682→        updatedAt: timestamp,
683→      })
684→      .where(eq(formatRules.id, ruleId))
685→      .run();
686→  });
687→
688→  const nextRule = getFormatRule(ruleId);
689→
690→  if (!nextRule) {
691→    throw new Error("Formatregel konnte nicht neu geladen werden.");
692→  }
693→
694→  return nextRule;
