696→
697→export function disableFormatRule(ruleId: string, importId?: string) {
698→  const existingRule = getFormatRule(ruleId);
699→
700→  if (!existingRule) {
701→    throw new Error("Formatregel nicht gefunden.");
702→  }
703→
704→  if (existingRule.status !== "active") {
705→    throw new Error("Nur aktive Regeln können deaktiviert werden.");
706→  }
707→
708→  const resolvedImportId = existingRule.importId ?? importId;
709→
710→  if (!resolvedImportId) {
711→    throw new Error(
712→      "Für Profil-Regeln muss eine gültige importId angegeben werden.",
713→    );
714→  }
715→
716→  db.transaction((tx) => {
717→    const timestamp = now();
718→
719→    tx.update(formatRules)
720→      .set({
721→        status: "disabled",
722→        updatedAt: timestamp,
723→      })
724→      .where(eq(formatRules.id, ruleId))
725→      .run();
726→
727→    recordAdjustmentEvent(
728→      {
729→        importId: resolvedImportId,
730→        ruleId: existingRule.id,
731→        sessionId: existingRule.sourceSessionId,
732→        targetFormat: existingRule.targetFormat,
733→        type: "rule_disabled",
734→      },
735→      tx,
736→    );
737→  });
738→
739→  const nextRule = getFormatRule(ruleId);
740→
741→  if (!nextRule) {
742→    throw new Error("Formatregel konnte nicht neu geladen werden.");
743→  }
744→
745→  return nextRule;
746→}
