614→// ---------------------------------------------------------------------------
615→// OpenAI helpers
616→// ---------------------------------------------------------------------------
617→
618→function isRecord(value: unknown): value is Record<string, unknown> {
619→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
620→}
621→
622→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
623→  if (!Array.isArray(payload.output)) {
624→    return [];
625→  }
626→
627→  return payload.output.flatMap((item) => {
628→    if (!isRecord(item) || item.type !== "function_call") {
629→      return [];
630→    }
631→
632→    const callId = typeof item.call_id === "string" ? item.call_id : null;
633→    const name = typeof item.name === "string" ? item.name : null;
634→    const args = typeof item.arguments === "string" ? item.arguments : null;
635→
636→    if (!callId || !name || !args) {
637→      return [];
638→    }
639→
640→    return [{ arguments: args, callId, name }];
641→  });
642→}
643→
644→function extractAssistantMessage(payload: ResponsesPayload) {
645→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
646→    return payload.output_text.trim();
647→  }
648→
649→  if (!Array.isArray(payload.output)) {
650→    return "";
651→  }
652→
653→  return payload.output
654→    .flatMap((item) => {
655→      if (
656→        !isRecord(item) ||
657→        item.type !== "message" ||
658→        item.role !== "assistant"
659→      ) {
660→        return [];
661→      }
662→
663→      const content = item.content;
664→      if (!Array.isArray(content)) {
665→        return [];
666→      }
667→
668→      return content.flatMap((entry) => {
669→        if (!isRecord(entry) || entry.type !== "output_text") {
670→          return [];
671→        }
672→
673→        return typeof entry.text === "string" && entry.text.trim()
674→          ? [entry.text.trim()]
675→          : [];
676→      });
677→    })
678→    .join("\n")
679→    .trim();
680→}
