422→// ---------------------------------------------------------------------------
423→// Context Builder
424→// ---------------------------------------------------------------------------
425→
426→function blockToPlainText(block: Block) {
427→  switch (block.type) {
428→    case "paragraph":
429→    case "heading":
430→    case "quote":
431→    case "code":
432→      return block.text;
433→    case "list":
434→      return block.items.join("\n");
435→    case "table":
436→      return [
437→        block.headers.join(" | "),
438→        ...block.rows.map((row) => row.join(" | ")),
439→      ].join("\n");
440→  }
441→}
442→
443→function summarizeSelection(
444→  sessionDetail: AdjustmentSessionDetail,
445→  job: ImportJob | undefined,
446→) {
447→  const { selection, targetFormat } = sessionDetail.session;
448→
449→  if (targetFormat === "markdown") {
450→    const markdown = job?.artifacts?.markdown ?? "";
451→    const lines = markdown.split("\n");
452→    const lineStart = selection.lineStart ?? 1;
453→    const lineEnd = selection.lineEnd ?? lineStart;
454→
455→    return {
456→      currentExcerpt:
457→        lines.slice(lineStart - 1, lineEnd).join("\n") ||
458→        selection.selectedText,
459→      description: `Markdown-Zeilen ${lineStart}-${lineEnd}`,
460→      surrounding: {
461→        next: lines[lineEnd] ?? null,
462→        previous: lineStart > 1 ? (lines[lineStart - 2] ?? null) : null,
463→      },
464→    };
465→  }
466→
467→  const message = job?.conversation?.messages.find(
468→    (entry) => entry.id === selection.messageId,
469→  );
470→  const currentBlock = message?.blocks[selection.blockIndex];
471→  const previousBlock =
472→    selection.blockIndex > 0
473→      ? message?.blocks[selection.blockIndex - 1]
474→      : undefined;
475→  const nextBlock = message?.blocks[selection.blockIndex + 1];
476→
477→  return {
478→    currentExcerpt: currentBlock
479→      ? blockToPlainText(currentBlock)
480→      : selection.selectedText,
481→    description: `${selection.messageRole} message ${selection.messageIndex + 1}, ${selection.blockType}`,
482→    surrounding: {
483→      next: nextBlock ? blockToPlainText(nextBlock) : null,
484→      previous: previousBlock ? blockToPlainText(previousBlock) : null,
485→    },
486→  };
487→}
488→
489→function buildSelectionContext(input: RunAgentTurnInput) {
490→  const { activeRules, job, sessionDetail } = input;
491→  const { selection, targetFormat } = sessionDetail.session;
492→  const selectionContext = summarizeSelection(sessionDetail, job);
493→  const lines: string[] = [];
494→
495→  lines.push("## Ausgewählter Block");
496→  lines.push(`Format: ${targetFormat}`);
497→  lines.push(
498→    `Block: ${selection.blockType} (messageId: "${selection.messageId}", blockId: "${selection.blockId ?? ""}", blockIndex: ${selection.blockIndex})`,
499→  );
500→  lines.push(
501→    `Rolle: ${selection.messageRole}, Nachricht ${selection.messageIndex + 1}`,
502→  );
503→  if (selection.lineStart != null) {
504→    lines.push(
505→      `Zeilen: ${selection.lineStart}-${selection.lineEnd ?? selection.lineStart}`,
506→    );
507→  }
508→  lines.push("");
509→  lines.push("Inhalt des ausgewählten Blocks:");
510→  lines.push("```");
511→  lines.push(selectionContext.currentExcerpt);
512→  lines.push("```");
513→
514→  if (selectionContext.surrounding.previous) {
515→    lines.push("");
516→    lines.push("Block davor:");
517→    lines.push(`> ${selectionContext.surrounding.previous.slice(0, 200)}`);
518→  }
519→  if (selectionContext.surrounding.next) {
520→    lines.push("");
521→    lines.push("Block danach:");
522→    lines.push(`> ${selectionContext.surrounding.next.slice(0, 200)}`);
523→  }
524→
525→  const active = activeRules
526→    .filter((rule) => rule.status === "active")
527→    .slice(0, 8);
528→  if (active.length > 0) {
529→    lines.push("");
530→    lines.push("## Bereits aktive Regeln");
531→    for (const rule of active) {
532→      const selectorStr = rule.selector
533→        ? JSON.stringify(rule.selector)
534→        : "(kein Selektor)";
535→      lines.push(
536→        `- [${rule.id}] ${rule.instruction ?? "(keine Beschreibung)"} — Selektor: ${selectorStr}`,
537→      );
538→    }
539→  }
540→
541→  const actionHistory = buildActionHistory(
542→    input.sessionEvents ?? [],
543→    activeRules,
544→  );
545→  if (actionHistory) {
546→    lines.push("");
547→    lines.push(actionHistory);
548→  }
549→
550→  return lines.join("\n");
551→}
552→
553→function buildActionHistory(
554→  sessionEvents: SessionEvent[],
555→  activeRules: FormatRule[],
556→): string {
557→  if (sessionEvents.length === 0) return "";
558→
559→  const ruleMap = new Map(activeRules.map((r) => [r.id, r]));
560→  const lines: string[] = ["## Deine bisherigen Aktionen in dieser Session"];
561→
562→  for (const [i, event] of sessionEvents.entries()) {
563→    const num = i + 1;
564→    const ruleId = event.ruleId ?? "unknown";
565→
566→    if (event.eventType === "rule_disabled") {
567→      lines.push(`${num}. Regel gelöscht (ID: ${ruleId})`);
568→    } else if (event.eventType === "rule_applied") {
569→      const rule = ruleMap.get(ruleId);
570→      const description = rule?.instruction ?? "(unbekannte Regel)";
571→      lines.push(`${num}. Regel erstellt: "${description}" (ID: ${ruleId})`);
572→    }
573→  }
574→
575→  return lines.join("\n");
576→}
577→
578→type InputMessage = {
579→  content: Array<{ text: string; type: "input_text" | "output_text" }>;
580→  role: "system" | "user" | "assistant";
581→};
582→
583→function buildInputMessages(input: RunAgentTurnInput): InputMessage[] {
584→  const targetFormat = input.sessionDetail.session.targetFormat;
585→  const messages: InputMessage[] = [
586→    {
587→      content: [{ text: buildSystemPrompt(targetFormat), type: "input_text" }],
588→      role: "system",
589→    },
590→    {
591→      content: [{ text: buildSelectionContext(input), type: "input_text" }],
592→      role: "user",
593→    },
594→  ];
595→
596→  // Add session messages as real multi-turn conversation so the model
597→  // understands the full dialog history and can reference prior turns.
598→  for (const msg of input.sessionDetail.messages) {
599→    const role = msg.role === "user" ? "user" : "assistant";
600→    messages.push({
601→      content: [
602→        {
603→          text: msg.content,
604→          type: role === "assistant" ? "output_text" : "input_text",
605→        },
606→      ],
607→      role,
608→    });
609→  }
610→
611→  return messages;
612→}
