614→// ---------------------------------------------------------------------------
615→// OpenAI helpers
616→// ---------------------------------------------------------------------------
617→
618→function isRecord(value: unknown): value is Record<string, unknown> {
619→  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
620→}
621→
622→function extractFunctionCalls(payload: ResponsesPayload): FunctionCallItem[] {
623→  if (!Array.isArray(payload.output)) {
624→    return [];
625→  }
626→
627→  return payload.output.flatMap((item) => {
628→    if (!isRecord(item) || item.type !== "function_call") {
629→      return [];
630→    }
631→
632→    const callId = typeof item.call_id === "string" ? item.call_id : null;
633→    const name = typeof item.name === "string" ? item.name : null;
634→    const args = typeof item.arguments === "string" ? item.arguments : null;
635→
636→    if (!callId || !name || !args) {
637→      return [];
638→    }
639→
640→    return [{ arguments: args, callId, name }];
641→  });
642→}
643→
644→function extractAssistantMessage(payload: ResponsesPayload) {
645→  if (typeof payload.output_text === "string" && payload.output_text.trim()) {
646→    return payload.output_text.trim();
647→  }
648→
649→  if (!Array.isArray(payload.output)) {
650→    return "";
651→  }
652→
653→  return payload.output
654→    .flatMap((item) => {
655→      if (
656→        !isRecord(item) ||
657→        item.type !== "message" ||
658→        item.role !== "assistant"
659→      ) {
660→        return [];
661→      }
662→
663→      const content = item.content;
664→      if (!Array.isArray(content)) {
665→        return [];
666→      }
667→
668→      return content.flatMap((entry) => {
669→        if (!isRecord(entry) || entry.type !== "output_text") {
670→          return [];
671→        }
672→
673→        return typeof entry.text === "string" && entry.text.trim()
674→          ? [entry.text.trim()]
675→          : [];
676→      });
677→    })
678→    .join("\n")
679→    .trim();
680→}
681→
682→async function requestOpenAiResponse(
683→  body: Record<string, unknown>,
684→  config: ReturnType<typeof readAdjustmentAiConfig>,
685→) {
686→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
687→    method: "POST",
688→    headers: {
689→      "Content-Type": "application/json",
690→      Authorization: `Bearer ${config.openai?.apiKey}`,
691→    },
692→    body: JSON.stringify({
693→      model: config.model,
694→      reasoning: { effort: "medium" },
695→      store: true,
696→      ...body,
697→    }),
698→    signal: AbortSignal.timeout(config.timeoutMs),
699→  });
700→
701→  if (!response.ok) {
702→    const errorText = await response.text();
703→    throw new AgentUnavailableError(
704→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
705→    );
706→  }
707→
708→  return (await response.json()) as ResponsesPayload;
709→}
710→
711→// ---------------------------------------------------------------------------
712→// Tool execution with validation
713→// ---------------------------------------------------------------------------
714→
715→function validateEffect(effect: unknown): {
716→  ok: boolean;
717→  data?: Record<string, unknown>;
718→  error?: string;
719→} {
720→  const result = customStyleEffectSchema.safeParse(effect);
721→  if (result.success) {
722→    return { ok: true, data: result.data as Record<string, unknown> };
723→  }
724→
725→  const issues = result.error.issues
726→    .map((i) => `${i.path.join(".")}: ${i.message}`)
727→    .join("; ");
728→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
729→}
730→
731→async function executeToolCall(
732→  call: FunctionCallItem,
733→  callbacks: RunAgentTurnInput["callbacks"],
734→  actions: ActionRecord[],
735→): Promise<string> {
736→  let args: Record<string, unknown>;
737→  try {
738→    args = JSON.parse(call.arguments) as Record<string, unknown>;
739→  } catch {
740→    return JSON.stringify({
741→      ok: false,
742→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
743→    });
744→  }
745→
746→  if (call.name === "create_rule") {
747→    const effectValidation = validateEffect(args.effect);
748→    if (!effectValidation.ok) {
749→      return JSON.stringify({ ok: false, error: effectValidation.error });
750→    }
751→
752→    try {
753→      const { ruleId } = await callbacks.onCreateRule({
754→        selector: args.selector as Record<string, unknown>,
755→        effect: effectValidation.data as Record<string, unknown>,
756→        description: String(args.description ?? ""),
757→      });
758→      actions.push({ type: "created", ruleId });
759→      return JSON.stringify({ ok: true, ruleId });
760→    } catch (error) {
761→      return JSON.stringify({
762→        ok: false,
763→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
764→      });
765→    }
766→  }
767→
768→  if (call.name === "update_rule") {
769→    const effectValidation = validateEffect(args.effect);
770→    if (!effectValidation.ok) {
771→      return JSON.stringify({ ok: false, error: effectValidation.error });
772→    }
773→
774→    const ruleId = String(args.ruleId ?? "");
775→
776→    try {
777→      await callbacks.onUpdateRule({
778→        ruleId,
779→        effect: effectValidation.data as Record<string, unknown>,
780→        description:
781→          typeof args.description === "string" ? args.description : undefined,
782→      });
783→      actions.push({ type: "updated", ruleId });
784→      return JSON.stringify({ ok: true, ruleId });
785→    } catch (error) {
786→      return JSON.stringify({
787→        ok: false,
788→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
789→      });
790→    }
791→  }
792→
793→  if (call.name === "delete_rule") {
794→    const ruleId = String(args.ruleId ?? "");
795→
796→    try {
797→      await callbacks.onDeleteRule(ruleId);
798→      actions.push({ type: "deleted", ruleId });
799→      return JSON.stringify({ ok: true, ruleId });
800→    } catch (error) {
801→      return JSON.stringify({
802→        ok: false,
803→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
804→      });
805→    }
806→  }
807→
808→  return JSON.stringify({
809→    ok: false,
810→    error: `Unbekannter Tool-Call: ${call.name}`,
811→  });
812→}
