198→function buildSelectorSchema(targetFormat: AdjustmentTargetFormat = "reader") {
199→  const isMarkdown = targetFormat === "markdown";
200→
201→  // For Markdown, compound selectors only support textPattern (line-based matching).
202→  // blockType, messageRole, headingLevel, position, and context are block/message
203→  // concepts that do not exist in the flat line-based Markdown representation and
204→  // are silently ignored by applyMarkdownRules. Exposing them would mislead the AI
205→  // into generating selectors that appear meaningful but have no effect.
206→  const compoundProperties = isMarkdown
207→    ? {
208→        textPattern: {
209→          type: "string",
210→          description:
211→            "Nur für compound: Regex-Pattern das im Markdown-Text matchen muss.",
212→        },
213→      }
214→    : {
215→        messageRole: {
216→          type: "string",
217→          enum: ["user", "assistant", "system", "tool"],
218→          description: "Nur für compound: Nachrichten dieser Rolle matchen.",
219→        },
220→        headingLevel: {
221→          type: "number",
222→          description: "Nur für compound: Überschriften-Ebene 1-6.",
223→        },
224→        position: {
225→          type: "string",
226→          enum: ["first", "last"],
227→          description:
228→            "Nur für compound: Erster oder letzter Block einer Nachricht.",
229→        },
230→        textPattern: {
231→          type: "string",
232→          description:
233→            "Nur für compound: Regex-Pattern das im Block-Text matchen muss.",
234→        },
235→        context: {
236→          type: "object",
237→          description: "Nur für compound: Nachbar-Block-Filter.",
238→          properties: {
239→            previousSibling: {
240→              type: "object",
241→              properties: {
242→                blockType: { type: "string" },
243→                headingLevel: { type: "number" },
244→                textPattern: { type: "string" },
245→              },
246→            },
247→            nextSibling: {
248→              type: "object",
249→              properties: {
250→                blockType: { type: "string" },
251→                headingLevel: { type: "number" },
252→                textPattern: { type: "string" },
253→              },
254→            },
255→          },
256→        },
257→      };
258→
259→  return {
260→    type: "object",
261→    properties: {
262→      strategy: {
263→        type: "string",
264→        enum: [
265→          "exact",
266→          "block_type",
267→          "prefix_before_colon",
268→          "markdown_table",
269→          "compound",
270→        ],
271→        description:
272→          "exact = nur dieser eine Block, block_type = alle Blöcke dieses Typs, compound = flexible Kombination aus Filtern.",
273→      },
274→      messageId: {
275→        type: "string",
276→        description: "ID der Nachricht (aus dem Kontext übernehmen).",
277→      },
278→      ...(targetFormat !== "markdown"
279→        ? {
280→            blockId: {
281→              type: "string",
282→              description: "ID des Blocks (aus dem Kontext übernehmen).",
283→            },
284→          }
285→        : {}),
286→      blockIndex: {
287→        type: "number",
288→        description: "Index des Blocks (aus dem Kontext übernehmen).",
289→      },
290→      blockType: {
291→        type: "string",
292→        enum: ["paragraph", "heading", "list", "quote", "code", "table"],
293→        description: "Typ des Blocks (aus dem Kontext übernehmen).",
294→      },
295→      lineStart: {
296→        type: "number",
297→        description: "Nur für Markdown: erste Zeile.",
298→      },
299→      lineEnd: {
300→        type: "number",
301→        description: "Nur für Markdown: letzte Zeile.",
302→      },
303→      ...compoundProperties,
304→    },
305→    required: ["strategy"],
306→  };
307→}
