682→async function requestOpenAiResponse(
683→  body: Record<string, unknown>,
684→  config: ReturnType<typeof readAdjustmentAiConfig>,
685→) {
686→  const response = await fetch(`${config.openai?.apiBaseUrl}/responses`, {
687→    method: "POST",
688→    headers: {
689→      "Content-Type": "application/json",
690→      Authorization: `Bearer ${config.openai?.apiKey}`,
691→    },
692→    body: JSON.stringify({
693→      model: config.model,
694→      reasoning: { effort: "medium" },
695→      store: true,
696→      ...body,
697→    }),
698→    signal: AbortSignal.timeout(config.timeoutMs),
699→  });
700→
701→  if (!response.ok) {
702→    const errorText = await response.text();
703→    throw new AgentUnavailableError(
704→      `Die Live-KI-Antwort war nicht verfügbar (${response.status}). ${errorText.slice(0, 240)}`,
705→    );
706→  }
707→
708→  return (await response.json()) as ResponsesPayload;
709→}
