711→// ---------------------------------------------------------------------------
712→// Tool execution with validation
713→// ---------------------------------------------------------------------------
714→
715→function validateEffect(effect: unknown): {
716→  ok: boolean;
717→  data?: Record<string, unknown>;
718→  error?: string;
719→} {
720→  const result = customStyleEffectSchema.safeParse(effect);
721→  if (result.success) {
722→    return { ok: true, data: result.data as Record<string, unknown> };
723→  }
724→
725→  const issues = result.error.issues
726→    .map((i) => `${i.path.join(".")}: ${i.message}`)
727→    .join("; ");
728→  return { ok: false, error: `Effect-Validierung fehlgeschlagen: ${issues}` };
729→}
730→
731→async function executeToolCall(
732→  call: FunctionCallItem,
733→  callbacks: RunAgentTurnInput["callbacks"],
734→  actions: ActionRecord[],
735→): Promise<string> {
736→  let args: Record<string, unknown>;
737→  try {
738→    args = JSON.parse(call.arguments) as Record<string, unknown>;
739→  } catch {
740→    return JSON.stringify({
741→      ok: false,
742→      error: `Ungültige Tool-Argumente: ${call.arguments}`,
743→    });
744→  }
745→
746→  if (call.name === "create_rule") {
747→    const effectValidation = validateEffect(args.effect);
748→    if (!effectValidation.ok) {
749→      return JSON.stringify({ ok: false, error: effectValidation.error });
750→    }
751→
752→    try {
753→      const { ruleId } = await callbacks.onCreateRule({
754→        selector: args.selector as Record<string, unknown>,
755→        effect: effectValidation.data as Record<string, unknown>,
756→        description: String(args.description ?? ""),
757→      });
758→      actions.push({ type: "created", ruleId });
759→      return JSON.stringify({ ok: true, ruleId });
760→    } catch (error) {
761→      return JSON.stringify({
762→        ok: false,
763→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
764→      });
765→    }
766→  }
767→
768→  if (call.name === "update_rule") {
769→    const effectValidation = validateEffect(args.effect);
770→    if (!effectValidation.ok) {
771→      return JSON.stringify({ ok: false, error: effectValidation.error });
772→    }
773→
774→    const ruleId = String(args.ruleId ?? "");
775→
776→    try {
777→      await callbacks.onUpdateRule({
778→        ruleId,
779→        effect: effectValidation.data as Record<string, unknown>,
780→        description:
781→          typeof args.description === "string" ? args.description : undefined,
782→      });
783→      actions.push({ type: "updated", ruleId });
784→      return JSON.stringify({ ok: true, ruleId });
785→    } catch (error) {
786→      return JSON.stringify({
787→        ok: false,
788→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
789→      });
790→    }
791→  }
792→
793→  if (call.name === "delete_rule") {
794→    const ruleId = String(args.ruleId ?? "");
795→
796→    try {
797→      await callbacks.onDeleteRule(ruleId);
798→      actions.push({ type: "deleted", ruleId });
799→      return JSON.stringify({ ok: true, ruleId });
800→    } catch (error) {
801→      return JSON.stringify({
802→        ok: false,
803→        error: error instanceof Error ? error.message : "Unbekannter Fehler.",
804→      });
805→    }
806→  }
807→
808→  return JSON.stringify({
809→    ok: false,
810→    error: `Unbekannter Tool-Call: ${call.name}`,
811→  });
812→}
