814→// ---------------------------------------------------------------------------
815→// Main agent turn
816→// ---------------------------------------------------------------------------
817→
818→export async function runAgentTurn(input: RunAgentTurnInput): Promise<{
819→  assistantMessage: string;
820→  actions: ActionRecord[];
821→}> {
822→  const config = readAdjustmentAiConfig();
823→
824→  if (!config.enabled || config.provider !== "openai" || !config.openai) {
825→    throw new AgentUnavailableError(
826→      "Live-KI-Anpassungen sind aktuell nicht konfiguriert. Hinterlege einen OpenAI-Zugang, bevor du diesen Chat nutzt.",
827→    );
828→  }
829→
830→  const actions: ActionRecord[] = [];
831→  const targetFormat = input.sessionDetail.session.targetFormat;
832→
833→  const inputMessages = buildInputMessages(input);
834→
835→  const isFirstTurn =
836→    input.sessionDetail.messages.filter((m) => m.role === "user").length <= 1;
837→
838→  let payload = await requestOpenAiResponse(
839→    {
840→      input: inputMessages,
841→      tool_choice: isFirstTurn ? "required" : "auto",
842→      tools: buildTools(targetFormat),
843→    },
844→    config,
845→  );
846→
847→  for (let round = 0; round < MAX_TOOL_ROUNDS; round += 1) {
848→    const functionCalls = extractFunctionCalls(payload);
849→    if (functionCalls.length === 0) {
850→      break;
851→    }
852→
853→    if (!payload.id) {
854→      throw new Error(
855→        "Die KI-Antwort enthält keine Response-ID für den Tool-Loop.",
856→      );
857→    }
858→
859→    const toolOutputs = [];
860→
861→    for (const call of functionCalls) {
862→      const result = await executeToolCall(call, input.callbacks, actions);
863→      toolOutputs.push({
864→        type: "function_call_output",
865→        call_id: call.callId,
866→        output: result,
867→      });
868→    }
869→
870→    payload = await requestOpenAiResponse(
871→      {
872→        input: toolOutputs,
873→        previous_response_id: payload.id,
874→        tool_choice: "auto",
875→        tools: buildTools(targetFormat),
876→      },
877→      config,
878→    );
879→  }
880→
881→  const rawMessage = extractAssistantMessage(payload);
882→  let assistantMessage: string;
883→
884→  if (rawMessage) {
885→    if (actions.length === 0 && !rawMessage.includes("?")) {
886→      // AI claims success without tool call → use honest fallback
887→      assistantMessage =
888→        "Ich konnte die Änderung leider nicht umsetzen. Kannst du genauer beschreiben, was du ändern möchtest?";
889→    } else {
890→      assistantMessage = rawMessage;
891→    }
892→  } else if (actions.length > 0) {
893→    assistantMessage = "Die Änderung ist jetzt sichtbar.";
894→  } else {
895→    // The AI returned no text and took no actions — retry once with an
896→    // explicit nudge so the user sees an actual question instead of a
897→    // generic placeholder.
898→    const retryPayload = await requestOpenAiResponse(
899→      {
900→        input: [
901→          ...inputMessages,
902→          {
903→            content: [
904→              {
905→                text: "Du hast gerade keine Antwort gegeben. Bitte stelle dem Nutzer jetzt eine konkrete Rückfrage, damit du eine passende Regel erstellen kannst.",
906→                type: "input_text",
907→              },
908→            ],
909→            role: "user",
910→          },
911→        ],
912→        tool_choice: "none",
913→        tools: buildTools(targetFormat),
914→      },
915→      config,
916→    );
917→
918→    assistantMessage =
919→      extractAssistantMessage(retryPayload) ||
920→      "Ich konnte die Anfrage nicht verstehen. Kannst du bitte genauer beschreiben, was du ändern möchtest?";
921→  }
922→
923→  return { assistantMessage, actions };
924→}
