      messageId: `msg-${sessionCounter}`,
      messageIndex: sessionCounter,
      messageRole: "assistant",
      selectedText: `Test content ${sessionCounter}`,
      textQuote: `Test content ${sessionCounter}`,
    },
    targetFormat: "reader",
  });
  createdSessionIds.push(session.id);
